How-To-Repeat: 
	Run following piece of the code:
=== cut here ===
#include <stdio.h>
#include <fcntl.h>
#include <sys/soundcard.h>

int main() {
	int fd, freq;

	if((fd = open("/dev/dsp", O_WRONLY))==-1) {
		printf("open %s failed.\n", "/dev/dsp");
		return(-1);
	}

	freq = 44100;
	printf("trying setting 44100hz...");
	if(ioctl(fd, SNDCTL_DSP_SPEED, &freq)==-1)
		freq = -1;
	printf("[%d]\n", freq);

	close(fd);
	return(0);
}
